         * METHOD TO GET THE KEYS FROM THE JSON DATA OBJECT
         * @method getKeys
         * @param  {Object} obj [ JSon object to get an array with the keys ]
         * @return {Array} keys [ key list from the json Object ]
         */
        function getKeys(obj) {
            var keys = [],
                i;

            for (i in obj) {
                if (obj.hasOwnProperty(i)) {
                    keys.push(i);
                }
            }

            return keys;
        }

